<section class="card"><form method="post" action="/users<?= !empty($row['id'])?'/'.e($row['id']):'' ?>"><?= csrf_field() ?><div class="form-grid"><label>Name<input name="name" value="<?= e($row['name'] ?? '') ?>"></label><label>Email<input type="email" name="email" value="<?= e($row['email'] ?? '') ?>"></label><label>Employee Code<input name="employee_code" value="<?= e($row['employee_code'] ?? '') ?>"></label><label>Phone<input name="phone" value="<?= e($row['phone'] ?? '') ?>"></label><label>Password<input type="password" name="password" placeholder="Leave blank to keep existing"></label><label>Status<select name="is_active"><option value="1" <?= ($row['is_active'] ?? 1)==1?'selected':'' ?>>Active</option><option value="0" <?= ($row['is_active'] ?? 1)==0?'selected':'' ?>>Inactive</option></select></label></div><h3>Roles</h3><div class="permissions"><?php foreach($roles as $role): ?><label><input type="checkbox" name="roles[]" value="<?= e($role['id']) ?>" <?= in_array($role['id'],$assigned)?'checked':'' ?>> <?= e($role['name']) ?></label><?php endforeach; ?></div><button class="primary">Save User</button></form></section>
